//! Purpose:
//! Builds callable descriptor support reused by eval-to-native constructor and
//! method bridges.
//!
//! Called from:
//! - `crate::codegen::finalize_user_asm()`.
//! - `crate::codegen::eval_constructor_helpers` and
//!   `crate::codegen::eval_method_helpers`.
//!
//! Key details:
//! - Eval stores PHP callbacks as boxed runtime values, while AOT callable
//!   parameters expect descriptor pointers.
//! - This bridge slice currently accepts string callables and selects static
//!   descriptors with uniform invokers generated by the existing callable
//!   dispatch machinery.

use crate::codegen::abi;
use crate::codegen::callable_descriptor::{
    self, CallableDescriptorInvocation, CallableDescriptorShape,
};
use crate::codegen::callable_dispatch::{self, RuntimeCallableCase, RuntimeCallableSelector};
use crate::codegen::data_section::DataSection;
use crate::codegen::emit::Emitter;
use crate::ir::{Function, LocalKind, Module};
use crate::names::function_symbol;
use crate::types::{callable_wrapper_sig, PhpType};

/// Callable descriptors available to eval constructor and method bridges.
pub(super) struct EvalCallableDescriptorSupport {
    cases: Vec<RuntimeCallableCase>,
}

impl EvalCallableDescriptorSupport {
    /// Returns true when no callable descriptor case is available.
    pub(super) fn is_empty(&self) -> bool {
        self.cases.is_empty()
    }
}

/// Returns true when eval bridges may need to turn PHP callbacks into descriptors.
pub(super) fn module_needs_eval_callable_descriptor_support(module: &Module) -> bool {
    module_uses_eval(module) && module_has_callable_aot_method_param(module)
}

/// Returns true when the EIR module contains a function that can call eval.
fn module_uses_eval(module: &Module) -> bool {
    all_module_functions(module).any(function_uses_eval)
}

/// Iterates every EIR function body emitted or inspected by the backend.
fn all_module_functions(module: &Module) -> impl Iterator<Item = &Function> {
    module
        .functions
        .iter()
        .chain(module.class_methods.iter())
        .chain(module.closures.iter())
        .chain(module.fiber_wrappers.iter())
        .chain(module.callback_wrappers.iter())
        .chain(module.extern_callback_trampolines.iter())
        .chain(module.runtime_callable_invokers.iter())
}

/// Returns true when a function has hidden eval state locals.
fn function_uses_eval(function: &Function) -> bool {
    function.locals.iter().any(|local| {
        matches!(
            local.kind,
            LocalKind::EvalContext | LocalKind::EvalScope | LocalKind::EvalGlobalScope
        )
    })
}

/// Returns true when any generated class callable exposed to eval accepts `callable`.
fn module_has_callable_aot_method_param(module: &Module) -> bool {
    module.class_infos.values().any(|class_info| {
        class_info.methods.values().any(signature_has_callable_param)
            || class_info
                .static_methods
                .values()
                .any(signature_has_callable_param)
    })
}

/// Returns true when one signature contains a callable ABI parameter.
fn signature_has_callable_param(signature: &crate::types::FunctionSig) -> bool {
    signature
        .params
        .iter()
        .any(|(_, ty)| ty.codegen_repr() == PhpType::Callable)
}

/// Emits shared runtime callable wrappers/invokers and returns descriptor cases.
pub(super) fn emit_eval_callable_descriptor_support(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    needed: bool,
) -> EvalCallableDescriptorSupport {
    if !needed {
        return EvalCallableDescriptorSupport { cases: Vec::new() };
    }
    let mut legacy_ctx = super::lower_inst::legacy_context_from_eir_module(module);
    legacy_ctx.functions.retain(|name, _| {
        module
            .functions
            .iter()
            .any(|function| !function.flags.is_main && function.name == *name)
    });
    let cases = eval_user_function_callable_cases(&mut legacy_ctx, data);
    emit_deferred_callable_support(emitter, data, &mut legacy_ctx);
    EvalCallableDescriptorSupport { cases }
}

/// Builds descriptor cases for user functions visible as eval string callables.
fn eval_user_function_callable_cases(
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
) -> Vec<RuntimeCallableCase> {
    let mut functions = legacy_ctx
        .functions
        .iter()
        .map(|(name, sig)| (name.clone(), sig.clone()))
        .collect::<Vec<_>>();
    functions.sort_by(|left, right| left.0.cmp(&right.0));
    let mut cases = Vec::with_capacity(functions.len());
    for (name, sig) in functions {
        let case_sig = callable_wrapper_sig(&sig);
        let invoker_label =
            callable_dispatch::ensure_runtime_descriptor_invoker(legacy_ctx, &[], &case_sig);
        let descriptor_label = callable_descriptor::static_descriptor_with_optional_invoker_meta(
            data,
            &function_symbol(&name),
            Some(&name),
            callable_descriptor::CALLABLE_DESC_KIND_FUNCTION,
            Some(&case_sig),
            &[],
            &[],
            CallableDescriptorInvocation::named(CallableDescriptorShape::Function, &name),
            invoker_label.as_deref(),
        );
        cases.push(RuntimeCallableCase {
            label: function_symbol(&name),
            descriptor_label,
            php_name: Some(name),
            sig: case_sig,
            captures: Vec::new(),
            has_invoker: invoker_label.is_some(),
            invoker_label,
        });
    }
    cases
}

/// Emits deferred callable support bodies behind one jump.
fn emit_deferred_callable_support(
    emitter: &mut Emitter,
    data: &mut DataSection,
    legacy_ctx: &mut crate::codegen::context::Context,
) {
    if legacy_ctx.deferred_closures.is_empty()
        && legacy_ctx.deferred_fiber_wrappers.is_empty()
        && legacy_ctx.deferred_callback_wrappers.is_empty()
        && legacy_ctx.deferred_extern_callback_trampolines.is_empty()
        && legacy_ctx.deferred_runtime_callable_invokers.is_empty()
    {
        return;
    }
    let done_label = legacy_ctx.next_label("eval_callable_support_done");
    abi::emit_jump(emitter, &done_label);
    crate::codegen::emit_deferred_closures(emitter, data, legacy_ctx);
    emitter.label(&done_label);
}

/// Converts the ARM64 boxed eval argument slot into a callable descriptor pointer.
pub(super) fn emit_aarch64_cast_eval_callable_arg(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
) {
    let string_label = format!("{}_callable_string", label_prefix);
    emitter.instruction("ldr x0, [x29, #-16]");                                 // reload the boxed eval argument for callable validation
    emitter.instruction("bl __rt_mixed_unbox");                                 // expose the eval callable tag and payload words
    emitter.instruction("cmp x0, #1");                                          // runtime tag 1 means a string callable name
    emitter.instruction(&format!("b.eq {}", string_label));                     // resolve string callables through descriptor metadata
    abi::emit_jump(emitter, fail_label);
    emitter.label(&string_label);
    abi::emit_push_reg_pair(emitter, "x1", "x2");
    emit_eval_string_callable_descriptor_lookup(
        module,
        emitter,
        data,
        support,
        label_prefix,
        fail_label,
        "x0",
    );
}

/// Converts the x86_64 boxed eval argument slot into a callable descriptor pointer.
pub(super) fn emit_x86_64_cast_eval_callable_arg(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
) {
    let string_label = format!("{}_callable_string", label_prefix);
    emitter.instruction("mov rax, QWORD PTR [rbp - 40]");                       // reload the boxed eval argument for callable validation
    emitter.instruction("call __rt_mixed_unbox");                               // expose the eval callable tag and payload words
    emitter.instruction("cmp rax, 1");                                          // runtime tag 1 means a string callable name
    emitter.instruction(&format!("je {}", string_label));                       // resolve string callables through descriptor metadata
    abi::emit_jump(emitter, fail_label);
    emitter.label(&string_label);
    abi::emit_push_reg_pair(emitter, "rdi", "rdx");
    emit_eval_string_callable_descriptor_lookup(
        module,
        emitter,
        data,
        support,
        label_prefix,
        fail_label,
        "rax",
    );
}

/// Looks up a descriptor by the string callable currently saved on the temp stack.
fn emit_eval_string_callable_descriptor_lookup(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
    result_reg: &str,
) {
    let done_label = format!("{}_callable_done", label_prefix);
    let miss_label = format!("{}_callable_missing", label_prefix);
    if support.is_empty() {
        abi::emit_release_temporary_stack(emitter, 16);
        abi::emit_jump(emitter, fail_label);
        return;
    }
    let selector = RuntimeCallableSelector::StringNameStack {
        ptr_offset: 0,
        len_offset: 8,
        call_reg: result_reg,
    };
    let mut legacy_ctx = super::lower_inst::legacy_context_from_eir_module(module);
    for case in &support.cases {
        let next_case = legacy_ctx.next_label("eval_callable_next");
        callable_dispatch::emit_branch_if_callable_case_mismatch(
            &selector,
            case,
            &next_case,
            emitter,
            &mut legacy_ctx,
            data,
        );
        abi::emit_jump(emitter, &done_label);
        emitter.label(&next_case);
    }
    abi::emit_jump(emitter, &miss_label);
    emitter.label(&miss_label);
    abi::emit_release_temporary_stack(emitter, 16);
    abi::emit_jump(emitter, fail_label);
    emitter.label(&done_label);
    abi::emit_release_temporary_stack(emitter, 16);
}
